import React from 'react';
import { NavLink, Link } from 'react-router-dom';
import { Home, BookOpen, Flag, Award, SquarePen, User, LogIn } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import './Header.css';

const Header = () => {
    const { currentUser } = useAuth();
    return (
        <header className="main-header">
            <Link to="/" className="logo">
                <img src="/images/logo-danang.svg" alt="Logo Đà Nẵng" className="logo-image" />
                <h1>ĐÀ NẴNG QUÊ HƯƠNG EM</h1>
            </Link>
            <nav>
                <NavLink to="/" className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}>
                    <Home size={24} />
                    <span>TRANG CHỦ</span>
                </NavLink>
                <NavLink to="/study" className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}>
                    <BookOpen size={24} />
                    <span>GÓC HỌC TẬP</span>
                </NavLink>
                <NavLink to="/tasks" className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}>
                    <Flag size={24} />
                    <span>NHIỆM VỤ</span>
                </NavLink>
                <NavLink to="/quiz" className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}>
                    <Award size={24} />
                    <span>KIỂM TRA</span>
                </NavLink>
                <NavLink to="/share" className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}>
                    <SquarePen size={24} />
                    <span>CHIA SẺ</span>
                </NavLink>
                <NavLink to="/profile" className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}>
                    <User size={24} />
                    <span>HỒ SƠ</span>
                </NavLink>
            </nav>
        </header>
    );
};

export default Header;

import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import {
    doc,
    getDoc,
    setDoc,
    updateDoc,
    increment,
    collection,
    query,
    where,
    getDocs,
    serverTimestamp,
    onSnapshot
} from 'firebase/firestore';
import { BarChart2 } from 'lucide-react';
import './VisitorCounter.css';
import { v4 as uuidv4 } from 'uuid'; // Generate unique ID for session

const VisitorCounter = () => {
    const [totalVisits, setTotalVisits] = useState(0);
    const [onlineUsers, setOnlineUsers] = useState(0);

    useEffect(() => {
        // 1. Logic Đếm Lượt Truy Cập (Total Visits) kèm Fallback LocalStorage
        const trackVisit = async () => {
            // Lấy số liệu cache tạm trên máy người dùng trước để tránh hiển thị 0
            const localCount = localStorage.getItem('visitorCount');
            if (localCount) {
                setTotalVisits(parseInt(localCount, 10));
            }

            try {
                const statsRef = doc(db, 'statistics', 'website_visits');
                const docSnap = await getDoc(statsRef);

                let currentCount = 0;

                // Nếu chưa có document thì tạo mới
                if (!docSnap.exists()) {
                    await setDoc(statsRef, { count: 0 }).catch(e => console.warn("Lưu firebase mới bị từ chối:", e));
                } else {
                    currentCount = docSnap.data().count;
                }

                // Tăng lượt đếm nếu đây là phiên truy cập mới 
                if (!sessionStorage.getItem('hasVisited')) {
                    const newCount = currentCount + 1;

                    // Thử lưu lên Firebase
                    try {
                        await updateDoc(statsRef, {
                            count: increment(1)
                        });
                        setTotalVisits(newCount);
                        localStorage.setItem('visitorCount', newCount.toString()); // Lưu Backup
                    } catch (fbError) {
                        console.warn("⚠️ Firebase chặn đếm (Permission Denied/Quota). Chuyển sang lưu cục bộ:", fbError);
                        // Fallback chỉ đếm trên máy hiện tại
                        const fallbackCount = parseInt(localCount || "0") + 1;
                        setTotalVisits(fallbackCount);
                        localStorage.setItem('visitorCount', fallbackCount.toString());
                    }

                    sessionStorage.setItem('hasVisited', 'true');
                }

                // Theo dõi dữ liệu real-time
                const unsubscribeVisits = onSnapshot(statsRef, (doc) => {
                    if (doc.exists() && doc.data().count > 0) {
                        const cloudCount = doc.data().count;
                        setTotalVisits(cloudCount);
                        localStorage.setItem('visitorCount', cloudCount.toString()); // Đồng bộ cloud về máy
                    }
                }, (error) => {
                    console.warn("⚠️ Không thể đọc Real-time Firebase:", error);
                });

                return unsubscribeVisits;
            } catch (error) {
                console.error("Lỗi hệ thống đếm truy cập:", error);
            }
        };

        const initTracking = async () => {
            await trackVisit();
        };
        initTracking();

    }, []);

    useEffect(() => {
        // 2. Logic Đếm Người Online (Sử dụng Heartbeat)
        let sessionId = sessionStorage.getItem('sessionId');
        if (!sessionId) {
            // Cài đặt thư viện uuid hoặc dùng math random
            sessionId = Math.random().toString(36).substring(2, 15);
            sessionStorage.setItem('sessionId', sessionId);
        }

        const onlineRef = doc(db, 'active_users', sessionId);

        const keepAlive = async () => {
            try {
                await setDoc(onlineRef, {
                    lastActive: serverTimestamp()
                });
            } catch (error) {
                console.error("Lỗi cập nhật Online:", error);
            }
        };

        // Gửi nhịp tim (heartbeat) lên firestore mỗi phút để báo đang online
        keepAlive();
        const heartbeatInterval = setInterval(keepAlive, 60000);

        // Đếm số lượng người có tín hiệu online 2 phút đổ lại đây
        const countOnlineUsers = () => {
            const usersRef = collection(db, 'active_users');
            const q = query(usersRef);

            return onSnapshot(q, (snapshot) => {
                let count = 0;
                // Nếu muốn chính xác có thể check timestamp < 2 mins. Nhưng do firestore security đôi khi block serverTimestamp comparison.
                // Hàm onSnapshot đếm mọi doc có trong bảng
                const now = new Date().getTime();
                snapshot.forEach((doc) => {
                    const data = doc.data();
                    if (data.lastActive) {
                        const lastActiveTime = data.lastActive.toDate?.()?.getTime() || data.lastActive.toMillis?.() || 0;
                        // Phải có hoạt động trong vòng 2 phút qua
                        if (now - lastActiveTime < 120000) {
                            count++;
                        }
                    } else {
                        // Fallback nếu serverTimestamp chưa update ngay
                        count++;
                    }
                });

                // Tránh lỗi chưa nạp kịp nên bị 0
                setOnlineUsers(Math.max(count, 1));
            });
        };

        const unsubscribeOnline = countOnlineUsers();

        // Cleanup: Xóa trạng thái online khi tắt trang web 
        // (Lưu ý: event unload không lúc nào cũng chạy đc FireStore API, nên dựa vào timestamp heartbeat là phụ chính).
        const handleUnload = async () => {
            // Không set await vì trang web sắp đóng
            setDoc(onlineRef, { status: "offline" });
        };
        window.addEventListener('beforeunload', handleUnload);

        return () => {
            clearInterval(heartbeatInterval);
            unsubscribeOnline();
            window.removeEventListener('beforeunload', handleUnload);
        };
    }, []);

    return (
        <div className="visitor-counter-container">
            <div className="visitor-header">
                <BarChart2 size={16} className="chart-icon" />
                <span>THỐNG KÊ</span>
            </div>
            <div className="visitor-divider"></div>
            <div className="visitor-stats">
                <div className="stat-row">
                    <span className="stat-label">Truy cập:</span>
                    <span className="stat-value">{totalVisits.toLocaleString('vi-VN')}</span>
                </div>
                <div className="stat-row">
                    <span className="stat-label">
                        <span className="online-dot"></span> Online:
                    </span>
                    <span className="stat-value online-value">{onlineUsers}</span>
                </div>
            </div>
        </div>
    );
};

export default VisitorCounter;

import React, { createContext, useContext, useState, useEffect } from 'react';
import {
    createUserWithEmailAndPassword,
    signInWithEmailAndPassword,
    signOut,
    onAuthStateChanged,
    GoogleAuthProvider,
    signInWithPopup
} from 'firebase/auth';
import { auth } from '../firebase';

const AuthContext = createContext();

export function useAuth() {
    return useContext(AuthContext);
}

export function AuthProvider({ children }) {
    const [currentUser, setCurrentUser] = useState(null);
    const [loading, setLoading] = useState(true);

    function signup(email, password) {
        return createUserWithEmailAndPassword(auth, email, password);
    }

    function login(email, password) {
        return signInWithEmailAndPassword(auth, email, password);
    }

    function logout() {
        return signOut(auth);
    }

    function loginWithGoogle() {
        const provider = new GoogleAuthProvider();
        return signInWithPopup(auth, provider);
    }

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, user => {
            setCurrentUser(user);
            setLoading(false);
        });

        return unsubscribe;
    }, []);

    const value = {
        currentUser,
        login,
        signup,
        logout,
        loginWithGoogle
    };

    return (
        <AuthContext.Provider value={value}>
            {!loading && children}
        </AuthContext.Provider>
    );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Mail, Lock, ArrowRight, Sparkles, BookOpen, GraduationCap } from 'lucide-react';
import './Login.css';

const Login = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const { login, signup, loginWithGoogle } = useAuth();
    const navigate = useNavigate();

    async function handleSubmit(e) {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            if (isLogin) {
                await login(email, password);
            } else {
                await signup(email, password);
            }
            navigate('/');
        } catch (err) {
            setError(isLogin ? 'Không thể đăng nhập. Vui lòng kiểm tra lại tài khoản!' : 'Lỗi khi tạo tài khoản. Mật khẩu phải từ 6 ký tự.');
            console.error(err);
        }

        setLoading(false);
    }

    async function handleGoogleLogin() {
        try {
            setError('');
            setLoading(true);
            await loginWithGoogle();
            navigate('/');
        } catch (err) {
            setError('Lỗi khi đăng nhập Google.');
            console.error(err);
        }
        setLoading(false);
    }

    const quickLogin = async (role) => {
        // Mock emails and passwords for quick login demonstration
        let targetEmail = role === 'teacher' ? 'giaovien@danang.edu.vn' : 'hocsinh@danang.edu.vn';
        let targetPass = '123456';

        setError('');
        setLoading(true);
        try {
            await login(targetEmail, targetPass);
            navigate('/');
        } catch (err) {
            // If accounts don't exist yet, we can create them on the fly for the sake of demo:
            try {
                await signup(targetEmail, targetPass);
                navigate('/');
            } catch (signupErr) {
                setError('Lối đăng nhập nhanh không khả dụng.');
                console.error(signupErr);
            }
        }
        setLoading(false);
    };

    return (
        <div className="login-wrapper">
            {/* Left Side: Branding */}
            <div className="login-brand-panel">
                <div className="brand-content">
                    <div className="logo-box">ĐN</div>
                    <h1 className="brand-title">ĐÀ NẴNG<br />QUÊ HƯƠNG EM</h1>

                    <div className="brand-divider"></div>

                    <h2 className="brand-subtitle">
                        TÀI LIỆU GIÁO DỤC ĐỊA PHƯƠNG 4<br />
                        <span className="subtitle-highlight">THÀNH PHỐ ĐÀ NẴNG</span>
                    </h2>

                    <p className="brand-quote">
                        “Hành trình khám phá lịch sử, địa lý<br />
                        và những nét đẹp văn hóa đặc sắc của thành phố Đà Nẵng.”
                    </p>

                    <div className="brand-icons">
                        <Sparkles size={24} />
                        <BookOpen size={24} />
                        <GraduationCap size={24} />
                    </div>
                </div>
            </div>

            {/* Right Side: Form */}
            <div className="login-form-panel">
                <div className="form-content-inner">
                    <h2 className="form-main-title">{isLogin ? 'TRẢI NGHIỆM NGAY!' : 'TẠO TÀI KHOẢN!'}</h2>
                    <p className="form-sub-text">Em hãy điền thông tin để bắt đầu hành trình học tập!</p>

                    {error && <div className="login-error-msg">{error}</div>}

                    <form onSubmit={handleSubmit} className="auth-form">
                        <div className="input-group">
                            <label>TÊN ĐĂNG NHẬP (EMAIL)</label>
                            <div className="input-wrapper">
                                <Mail size={18} className="input-icon" />
                                <input
                                    type="email"
                                    placeholder="an@gmail.com"
                                    required
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="input-group">
                            <label>MẬT KHẨU</label>
                            <div className="input-wrapper">
                                <Lock size={18} className="input-icon" />
                                <input
                                    type="password"
                                    placeholder="••••••••"
                                    required
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                />
                            </div>
                        </div>

                        <button disabled={loading} type="submit" className={isLogin ? "submit-auth-btn" : "submit-auth-btn register"}>
                            {isLogin ? 'ĐĂNG NHẬP' : 'ĐĂNG KÝ'} <ArrowRight size={20} className="arrow-icon" />
                        </button>
                    </form>

                    <p className="toggle-auth-link">
                        {isLogin ? 'Chưa có tài khoản? ' : 'Đã có tài khoản? '}
                        <span onClick={() => setIsLogin(!isLogin)}>
                            {isLogin ? 'Đăng ký ngay' : 'Đăng nhập ngay'}
                        </span>
                    </p>

                    <div className="section-divider google-divider">
                        <span>HOẶC</span>
                    </div>

                    <button
                        disabled={loading}
                        onClick={handleGoogleLogin}
                        className="google-auth-btn"
                    >
                        <img src="https://upload.wikimedia.org/wikipedia/commons/c/c1/Google_%22G%22_logo.svg" alt="Google" />
                        Tiếp tục với Google
                    </button>

                    {isLogin && (
                        <div className="quick-login-section">
                            <div className="section-divider">
                                <span>ĐĂNG NHẬP NHANH (TÀI KHOẢN MẪU)</span>
                            </div>

                            <button className="quick-acc-btn" onClick={() => quickLogin('teacher')} disabled={loading}>
                                <div className="quick-avatar teacher-avatar">👩‍🏫</div>
                                <div className="quick-info">
                                    <span className="quick-name">GIÁO VIÊN</span>
                                    <span className="quick-role">GIÁO VIÊN</span>
                                </div>
                            </button>

                            <button className="quick-acc-btn" onClick={() => quickLogin('student')} disabled={loading}>
                                <div className="quick-avatar student-avatar">👦</div>
                                <div className="quick-info">
                                    <span className="quick-name">NGUYỄN VĂN AN</span>
                                    <span className="quick-role">HỌC SINH</span>
                                </div>
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Login;

